import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Categorias() {
    const [categorias, setCategorias] = useState([]);
    const [form, setForm] = useState({ id: null, nome: '', preco_sugerido: '', tempo_estimado_minutos: '' });
    const [editando, setEditando] = useState(false);

    const carregar = async () => {
        const res = await api.get('/categorias');
        setCategorias(res.data);
    };

    useEffect(() => { carregar(); }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const payload = { nome: form.nome, preco_sugerido: form.preco_sugerido ? parseFloat(form.preco_sugerido) : null, tempo_estimado_minutos: form.tempo_estimado_minutos ? parseInt(form.tempo_estimado_minutos) : null };
            if (editando) await api.put(`/categorias/${form.id}`, payload);
            else await api.post('/categorias', payload);
            setForm({ id: null, nome: '', preco_sugerido: '', tempo_estimado_minutos: '' });
            setEditando(false);
            carregar();
        } catch (err) { alert('Erro ao salvar'); }
    };

    const handleEdit = (c) => { setForm({ id: c.id, nome: c.nome, preco_sugerido: c.preco_sugerido || '', tempo_estimado_minutos: c.tempo_estimado_minutos || '' }); setEditando(true); };
    const handleDelete = async (id) => {
        if (window.confirm('Excluir categoria?')) { await api.delete(`/categorias/${id}`); carregar(); }
    };

    return (
        <div>
            <h2>Categorias</h2>
            <form onSubmit={handleSubmit} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '20px' }}>
                <input type="text" placeholder="Nome" value={form.nome} onChange={e => setForm({...form, nome: e.target.value})} required />
                <input type="number" step="0.01" placeholder="Preço sugerido" value={form.preco_sugerido} onChange={e => setForm({...form, preco_sugerido: e.target.value})} />
                <input type="number" placeholder="Tempo (min)" value={form.tempo_estimado_minutos} onChange={e => setForm({...form, tempo_estimado_minutos: e.target.value})} />
                <button type="submit">{editando ? 'Atualizar' : 'Cadastrar'}</button>
                {editando && <button type="button" onClick={() => { setForm({ id: null, nome: '', preco_sugerido: '', tempo_estimado_minutos: '' }); setEditando(false); }}>Cancelar</button>}
            </form>
            <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead><tr><th>Nome</th><th>Preço sugerido</th><th>Tempo (min)</th><th>Ações</th></tr></thead>
                <tbody>
                    {categorias.map(c => (
                        <tr key={c.id}>
                            <td>{c.nome}</td><td>R$ {c.preco_sugerido}</td><td>{c.tempo_estimado_minutos}</td>
                            <td><button onClick={() => handleEdit(c)}>Editar</button> <button onClick={() => handleDelete(c.id)}>Excluir</button></td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Categorias;
